# Create a requirements.txt file for your data science project that uses both PyPI packages and internal tools
import subprocess
from typing import List

# Define the package names
packages = [
    "numpy",  # Numerical Python, popular library for working with arrays
    "pandas",  # Powerful data structures for manipulating structured data
    "scikit-learn",  # Machine learning in Python
    "tensorflow",  # Google's machine learning framework
]
internal_tools = ["data-utils", "ml-helpers", "company-datasets"]  # Replace these with actual internal tool names

def generate_requirements(packages: List[str], tools: List[str]) -> None:
    with open("requirements.txt", "w") as file:
        for package in packages:
            command = f"pip show {package}"
            output = subprocess.check_output(command, shell=True).decode().strip()
            version = output.split("\n")[-1] if "\n" in output else ""
            file.write(f"{package}=={version}\n")  # Write latest versions to the requirements.txt
        for tool in tools:
            file.write(f"{tool}\n")
generate_requirements(packages, internal_tools)